const input = $input.first().json;
const payload = input.body ?? input.payload ?? input;

return [{
  json: {
    ...input,
    payload,
    job_id: input.job_id ?? payload.job_id ?? payload?.job?.id,
    project_id: input.project_id ?? payload.project_id ?? payload?.project?.id,
    user_id: input.user_id ?? payload.user_id ?? payload?.user?.id,
    diagnosis_id: input.diagnosis_id ?? payload.diagnosis_id ?? payload?.diagnosis?.id,
    objective_id: input.objective_id ?? payload.objective_id ?? payload?.objective?.id,
    diagnosis_result: input.diagnosis_result ?? payload.diagnosis_result ?? payload?.diagnosisResult ?? {},
    objective_input: input.objective_input ?? payload.objective_input ?? payload?.objectiveInput ?? {}
  }
}];

const input = $input.first().json;
const rawBody = JSON.stringify(input.body ?? input.payload ?? input);

const expected = await (async () => {
  const encoder = new TextEncoder();
  const secret = $env.N8N_WEBHOOK_SECRET;
  const key = await globalThis.crypto.subtle.importKey(
    'raw',
    encoder.encode(secret),
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign']
  );
  const signatureBuffer = await globalThis.crypto.subtle.sign('HMAC', key, encoder.encode(rawBody));
  return Array.from(new Uint8Array(signatureBuffer))
    .map((byte) => byte.toString(16).padStart(2, '0'))
    .join('');
})();

if (expected !== input.app_signature) {
  throw new Error('Invalid app signature');
}

return [{
  json: {
    ...input,
    verified: true
  }
}];

const raw = typeof query === 'string' ? query : JSON.stringify(query ?? {});
let parsed;
try {
  parsed = JSON.parse(raw);
} catch {
  parsed = { raw };
}

return JSON.stringify({
  reminder: 'Make the SMART objective specific, measurable, realistic, and linked to the diagnosis.',
  time_period: parsed.business_goal?.target_period ?? null,
  traffic_target: parsed.seo_baseline?.monthly_organic_traffic ?? null,
  constraint_notes: parsed.constraints ?? {}
});

const input = $input.first().json;
const rawOutput = input.output ?? input.text ?? input.response ?? input.result ?? input;

let parsed = rawOutput;
if (typeof rawOutput === 'string') {
  try {
    parsed = JSON.parse(rawOutput);
  } catch {
    parsed = null;
  }
}

if (!parsed || typeof parsed !== 'object') {
  parsed = {
    objective_type: 'mixed',
    smart_objective: typeof rawOutput === 'string' ? rawOutput : 'AI output could not be parsed.',
    business_goal_alignment: 'Review the AI output and rerun the workflow.',
    input_metrics: input.objective_input ?? {},
    output_metrics: {},
    outcome_metrics: {},
    baseline: input.objective_input?.seo_baseline ?? {},
    target: {},
    time_period: input.objective_input?.business_goal?.target_period ?? null,
    achievability_score: 'unknown',
    achievability_percent: 0,
    risk_notes: ['AI output was not valid JSON'],
    reasoning: 'The AI response was not valid JSON.',
    next_step: 'Inspect the AI Agent output and regenerate the objective.',
    raw_llm_output: rawOutput,
    model_used: 'n8n-ai-agent'
  };
}

return [{
  json: {
    ...input,
    objective_result: parsed
  }
}];

const input = $input.first().json;
const objectiveResult = input.objective_result ?? {};
const now = new Date().toISOString();

const supabaseObjectivePayload = {
  objective_type: objectiveResult.objective_type,
  smart_objective: objectiveResult.smart_objective,
  business_goal_alignment: objectiveResult.business_goal_alignment ?? null,
  input_metrics: objectiveResult.input_metrics ?? {},
  output_metrics: objectiveResult.output_metrics ?? {},
  outcome_metrics: objectiveResult.outcome_metrics ?? {},
  baseline: objectiveResult.baseline ?? {},
  target: objectiveResult.target ?? {},
  time_period: objectiveResult.time_period ?? null,
  achievability_score: objectiveResult.achievability_score ?? null,
  achievability_percent: objectiveResult.achievability_percent ?? null,
  risk_notes: objectiveResult.risk_notes ?? [],
  reasoning: objectiveResult.reasoning ?? null,
  next_step: objectiveResult.next_step ?? null,
  raw_llm_output: objectiveResult.raw_llm_output ?? {},
  model_used: objectiveResult.model_used,
  status: 'completed',
  completed_at: now
};

const supabaseJobPayload = {
  status: 'completed',
  response_payload: objectiveResult,
  completed_at: now
};

const supabaseUsageEventPayload = {
  user_id: input.user_id,
  event_type: 'objective_generated',
  metadata: {
    jobId: input.job_id,
    projectId: input.project_id,
    objectiveId: input.objective_id,
    source: 'n8n-objective-workflow'
  }
};

return [{
  json: {
    ...input,
    supabase_objective_payload: supabaseObjectivePayload,
    supabase_job_payload: supabaseJobPayload,
    supabase_usage_event_payload: supabaseUsageEventPayload
  }
}];

